<template>
	<view class="body">
		<status-bar />
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<!-- <image class="logo" :src="sysconfig.icoimg" mode="aspectFit"></image> -->
		<view style="display: flex;justify-content: center;padding-top:20rpx;">

			<u-image :src="sysconfig.logo" width="360rpx" height="160rpx" mode="aspectFit"
				@click="$util.on('/pages/index/index')" />
		</view>
		<view class="title">
			重置密码
			<view class="change-type-box" @click="changeResetType">
				{{currFindName}}
			</view>
		</view>
		<view class="form" v-if="findList.length">
			<view class="form-item" v-if="currFindType == 'mobile'">
				<view class="input">
					<u-input v-model="mobile" type="text" placeholder="请输入手机号" height="40" />
				</view>
			</view>
			<view class="form-item" v-else-if="currFindType == 'email'">
				<view class="input">
					<u-input v-model="email" type="text" placeholder="请输入邮箱" height="40" />
				</view>
			</view>
			<view class="form-item">
				<view class="input" style="width:360rpx">
					<u-input v-model="validateCode" type="text" maxlength="6" placeholder="请输入验证码" height="40" />
				</view>
				<view class="" :style="is_sendCode?'color:#c3c8d9;':'color:red;'" @click="sendCode(12)">
					<u-verification-code :seconds="seconds" ref="uCode" @start="codeStart" @end="codeEnd"
						@change="codeChange" start-text="获取验证码" change-text="X秒"></u-verification-code>
					<view class="">
						{{tips}}
					</view>
				</view>
			</view>
			<view class="form-item">
				<view class="input">
					<u-input v-model="pwd" type="password" placeholder="请输入新密码" height="40" />
				</view>
			</view>
			<view class="form-item">
				<view class="input">
					<u-input v-model="pwd1" type="password" placeholder="请确认新密码" height="40" />
				</view>
			</view>
			<view class="other">
				<text></text>
				<text @click="$util.on('/pages/user/login')">返回登录</text>
			</view>
			<view class="login-button" @click="$u.throttle(doSubmit, 500)">
				立即重置
			</view>
		</view>
	</view>
</template>
<script>
	import slideCode from '@/components/slideCode.vue'
	import StatusBar from '@/components/my-page-header/status-bar'
	import {
		mapGetters
	} from 'vuex'

	export default {
		components: {
			slideCode,
			StatusBar
		},
		data() {
			return {
				reset_type: 1, //重置密码方式：1手机号码+验证码，2：邮箱+验证码

				username: '', //账号
				pwd: '', //密码
				pwd1: '', //密码
				session_id: [], //会自动生成的
				pid: '', //上级ID
				validateCode: '',
				mobile: '',
				slideCode: [{
					show: false
				}],
				tips: '',
				seconds: 60,
				is_sendCode: false, //是否发送验证码

				email: '',

				resetIndex: -1
			};
		},
		computed: {
			...mapGetters({
				retrievePasswordConfigType: 'loginConfig/retrievePasswordConfigType'
			}),
			findList() {
				let re = []
				this.retrievePasswordConfigType.map((item) => {
					if (item == 'mobile') {
						re.push({
							name: 'mobile',
							label: '手机号码找回'
						})
					} else if (item == 'email') {
						re.push({
							name: 'email',
							label: '邮箱找回'
						})
					}
				})
				return re
			},
			currFindName() {
				if (this.resetIndex != -1) {
					return this.findList[this.resetIndex].label
				} else {
					return ''
				}
			},
			currFindType() {
				if (this.resetIndex != -1) {
					return this.findList[this.resetIndex].name
				} else {
					return ''
				}
			}
		},
		onLoad() {
			if (this.findList.length) {
				this.resetIndex = 0
			}
			this.$slideCode_init(0); //初始化图形滑块
		},
		methods: {
			// 改变密码找回方式
			changeResetType() {
				if (this.resetIndex == this.findList.length - 1) {
					this.resetIndex = 0
				} else {
					this.resetIndex++
				}
			},


			codeChange(text) {
				this.tips = text;
			},

			//发送验证码
			sendCode() {
				if (this.currFindType == 'mobile') {
					if (!this.$u.test.mobile(this.mobile)) return this.$u.toast('请输入正确的手机号')
				} else if (this.currFindType == 'email') {
					if (!this.$u.test.email(this.email)) return this.$u.toast('请输入正确的邮箱')
				}
				this.slideCode[0].show = true; //滑块验证码
			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			canGetCode() {
				if (this.$refs.uCode.canGetCode) {
					if (this.currFindType == 'mobile') {
						let data = {
							send_type: 12,
							mobile: this.mobile,
							session: this.session_id[0],
						}
						this.$u.api.sendCode(data).then(res => {
							this.$u.toast('验证码已发送')
							this.$refs.uCode.start();
						}).catch((res) => {
							this.$u.toast(res.data.msg)
						})
					} else if (this.currFindType == 'email') {
						this.$u.api.sendEmailCode({
							event: 'resetpwd',
							email: this.email,
							session: this.session_id[0]
						}).then(res => {
							this.$u.toast('验证码已发送')
							this.$refs.uCode.start();
						}).catch((res) => {

							this.$u.toast(res.data.msg)
						})
					}

				} else {
					this.$u.toast('倒计时结束后再发送')
				}
			},
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值
				this.canGetCode()
			},
			async doSubmit() {
				if (this.currFindType == 'mobile') {
					if (!this.$u.test.mobile(this.mobile)) return this.$u.toast('请输入正确的手机号')
				} else if (this.currFindType == 'email') {
					if (!this.$u.test.email(this.email)) return this.$u.toast('请输入正确的邮箱')
				}
				if (!this.validateCode || this.validateCode == '') {
					this.$util.msg('请输入验证码');
					return;
				}
				if (!this.pwd) {
					this.$util.msg('请输入密码');
					return;
				}

				if (!this.pwd1) {
					this.$util.msg('请输入确认密码');
					return;
				}

				if (this.pwd != this.pwd1) {
					this.$util.msg('两次密码不一致');
					return;
				}

				await this.$u.api.resetpwd({
					resetType: this.currFindType,
					email: this.email,
					mobile: this.mobile,
					password: this.pwd,
					password1: this.pwd1,
					validateCode: this.validateCode,
				})

				this.$util.msg('重置成功')
				setTimeout(() => {
					this.$util.back();
				}, 1000)
			}
		}
	};
</script>
<style scoped>
	page {
		background-color: #fff;
		width: 100%;
		height: 100%;
		overflow: auto;
		position: fixed;
		top: 0;
		left: 0;
	}
</style>
<style lang="scss" scoped scoped>
