			margin-top: 16rpx;

			.change-type-box {
				float: right;
				font-size: 26rpx;
				margin-top: 16rpx;
				margin-right: 40rpx;
				color: red;
				font-weight: 400;
				cursor: pointer;
			}
		}

		.logo {
			margin-top: 104rpx;
			margin-left: 86rpx;
