				.register {
					color: #ff594d;
				}
			}
		}


		.third-box {

			width: 100%;
			margin-top: 120rpx;
			display: flex;
			align-items: center;
			justify-content: flex-start;
			flex-direction: column;
			gap: 20rpx;

			.text {
				font-weight: 400;
				color: #9b9fa8;
