				background: #D6DAE2;
				position: absolute;
				display: block;
				top: 50%;
				transform: translateY(-50%);
				right: 200rpx;
			}

			.text::after {
				content: "";
				width: 140rpx;
				height: 2rpx;
				background: #D6DAE2;
				position: absolute;
				display: block;
				top: 50%;
				transform: translateY(-50%);
				left: 200rpx;
			}





			.third-list {
				display: flex;
				align-items: center;
				justify-content: center;
				gap: 110rpx;

				.third-logo {
					width: 64rpx;
					height: 64rpx;
					color: #cacdd5;
				}
			}





		}
	}
</style>